    @NotNull
    public static Optional<Item> retrieve(@NotNull CloudResourceLocation cloudRes) {
        return BFItems.retrieve(ResourceLocation.fromNamespaceAndPath((String)cloudRes.namespace(), (String)cloudRes.path()));
    }

    @NotNull
    public static Optional<Item> retrieve(@NotNull ResourceLocation res) {
        return BuiltInRegistries.ITEM.getOptional(res);
    }

    static {
        for (DeferredHolder deferredHolder : BFBlocks.DR.getEntries()) {
            DR.register(deferredHolder.getId().getPath(), () -> new BlockItem((Block)deferredHolder.get(), new Item.Properties()));
        }
        for (DeferredHolder deferredHolder : BFBlocks.DR_GEN.getEntries()) {
            DR.register(deferredHolder.getId().getPath(), () -> new BlockItem((Block)deferredHolder.get(), new Item.Properties()));
        }
    }
